package main

import (
	"context"
	"fmt"
	"log/slog"

	primitives "github.com/bsv-blockchain/go-sdk/primitives/ec"
	"github.com/bsv-blockchain/go-sdk/script"
	"github.com/bsv-blockchain/go-sdk/transaction"
	feemodel "github.com/bsv-blockchain/go-sdk/transaction/fee_model"
	"github.com/bsv-blockchain/go-sdk/transaction/template/p2pkh"

	"github.com/bsv-blockchain/go-wallet-toolbox/examples/internal/show"
	"github.com/bsv-blockchain/go-wallet-toolbox/pkg/defs"
	"github.com/bsv-blockchain/go-wallet-toolbox/pkg/services"
)

// This example demonstrates broadcasting a BSV transaction using multiple wallet services
// Creates a new transaction from a BEEF-encoded source and submits it for network propagation
func main() {
	const (
		wif = "cQFwZHWLNTd31aE8ZPtJ48gxQFg3PPSEyrumghwNN3znjARNgLYX"

		// This transaction is already spent, so please use your own transaction.
		sourceTxBEEF      = ""
		sourceOutputIndex = uint32(0)

		network = defs.NetworkTestnet
	)

	show.ProcessStart("Post BEEF")

	// Set to LevelDebug to see http request logs
	// slog.SetLogLoggerLevel(slog.LevelDebug)

	show.Step("Transaction", "preparing transaction from BEEF source")

	tx, err := prepareTransaction(sourceTxBEEF, wif, sourceOutputIndex, network)
	if err != nil {
		panic(err)
	}

	beef, err := transaction.NewBeefFromTransaction(tx)
	if err != nil {
		panic(err)
	}

	serviceCfg := defs.DefaultServicesConfig(network)
	walletServices := services.New(slog.Default(), serviceCfg)

	show.Step("Wallet-Services", fmt.Sprintf("broadcasting transaction %s", tx.TxID().String()))

	results, err := walletServices.PostFromBEEF(context.Background(), beef, []string{tx.TxID().String()})
	if err != nil {
		panic(err)
	}

	show.Success("Posted BEEF to services")
	show.PostBEEFOutput(results)

	show.ProcessComplete("Post BEEF")
}

func prepareTransaction(sourceTxBEEF, wif string, sourceOutputIndex uint32, network defs.BSVNetwork, outputsSatoshis ...uint64) (*transaction.Transaction, error) {
	sourceTx, err := transaction.NewTransactionFromBEEFHex(sourceTxBEEF)
	if err != nil {
		return nil, fmt.Errorf("could not prepare transaction: %w", err)
	}

	priv, err := primitives.PrivateKeyFromWif(wif)
	if err != nil {
		return nil, fmt.Errorf("could not prepare transaction: %w", err)
	}

	tx := transaction.NewTransaction()

	unlockingScript, err := p2pkh.Unlock(priv, nil)
	if err != nil {
		return nil, fmt.Errorf("could not prepare transaction: %w", err)
	}

	tx.AddInputFromTx(sourceTx, sourceOutputIndex, unlockingScript)

	address, err := script.NewAddressFromPublicKey(priv.PubKey(), network == defs.NetworkMainnet)
	if err != nil {
		return nil, fmt.Errorf("could not prepare transaction: %w", err)
	}

	lockingScript, err := p2pkh.Lock(address)
	if err != nil {
		return nil, fmt.Errorf("could not prepare transaction: %w", err)
	}

	tx.AddOutput(&transaction.TransactionOutput{
		LockingScript: lockingScript,
		Change:        true,
	})

	for _, outputSatoshis := range outputsSatoshis {
		tx.AddOutput(&transaction.TransactionOutput{
			LockingScript: lockingScript,
			Satoshis:      outputSatoshis,
		})
	}

	err = tx.Fee(&feemodel.SatoshisPerKilobyte{Satoshis: 1}, transaction.ChangeDistributionEqual)
	if err != nil {
		return nil, fmt.Errorf("could not prepare transaction: %w", err)
	}

	err = tx.Sign()
	if err != nil {
		return nil, fmt.Errorf("could not prepare transaction: %w", err)
	}
	return tx, nil
}
